        // --- Stabilne ID (z hasha cat+desc, NIE z 'name' - nazwy zmieniaja sie dla zabawy, opis nie) ---
        // Sluzy do trwalego zapisu odblokowanych osiagniec (achievements-data.js), zeby przezyly
        // pozniejsze zmiany danych referencyjnych (np. VISA_PL po odswiezeniu).
        (function(){
            function _achHash(s){
                var h = 0;
                for (var i = 0; i < s.length; i++) { h = (h * 31 + s.charCodeAt(i)) | 0; }
                return "ach_" + (h >>> 0).toString(36);
            }
            window.ACHIEVEMENTS.forEach(function(a){ a.id = _achHash(a.cat + "|" + a.desc); });
        })();
